import React, { useState } from 'react';
import { Modal, Button } from 'react-bootstrap';
import makeAnimated from 'react-select/animated';
import Select from 'react-select';
import {Icon} from 'react-icons-kit';
import {eyeOff} from 'react-icons-kit/feather/eyeOff';
import {eye} from 'react-icons-kit/feather/eye'
import { validateCurrentStep} from '../../utils/validation';
import { useTranslation } from 'react-i18next';
import axios from 'axios'

const formlength = {
  'patient': [6,10,12,19],
  'therapist': [6,8],
  'researcher': [6,8]
}
const options = [
  { value: 'chocolate', label: 'Chocolate' },
  { value: 'strawberry', label: 'Strawberry' },
  { value: 'vanilla', label: 'Vanilla' }
]

interface FormData {
  email: string;
  password: string;
  repeatPassword: string;
  userType: string;
  firstName: string;
  lastName: string;
  [key: string]: string | number | string[] | boolean ; // For any additional dynamic fields
}
interface RegisterFormProps {
  show: boolean;
  handleRegShow: () => void;
}
const FormRegister: React.FC<RegisterFormProps> = ({ show, handleRegShow }) => {

  const {t} = useTranslation();
  const userTypes = Object.keys(t('userTypes', { returnObjects: true }));
  // State for storing the form data
  const [formData, setFormData] = useState<FormData>({
    email: '',
    password: '',
    repeatPassword: '',
    userType: '',
    firstName: '',
    lastName: '',
  });

  const [icon, setIcon] = useState(eyeOff);
  const [showPassword, setShowPassword] = useState(false);
  const [passwordError, setPasswordError] = useState('');
  const [registered, setRegistered] = useState(false);
  const [iconRepeat, setIconRepeat] = useState(eyeOff);
  const [showPasswordRepeat, setShowPasswordRepeat] = useState(false);

  const handleToggle = () => {
    if (!showPassword){
      setIcon(eye);
      setShowPassword(true)
    } else {
      setIcon(eyeOff)
      setShowPassword(false)
    }
  }
  const handleToggleRepeat = () => {
    if (!showPasswordRepeat){
      setIconRepeat(eye);
      setShowPasswordRepeat(true)
    } else {
      setIconRepeat(eyeOff)
      setShowPasswordRepeat(false)
    }
  }
  const [errors, setErrors] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    repeatPassword: '',
  });

  // State to manage if "Next" was clicked and render additional fields
  const [step, setStep] = useState(1);
  const [valid, setValid] = useState(false);
  // Handle form input changes
  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { id, value } = e.target;
    setFormData({ ...formData, [id]: value });
  };
  const animatedComponents = makeAnimated();

  // Handle the "Back" button click
  const handleBack = () => {
      setStep(step - 1); // Move to the next step when "Next" is clicked
  };

  const handleModalClose = () => {
    handleRegShow();  // This will hide the modal (assuming it toggles the `show` state)
    setStep(1);       // This will reset the step to 1
    // Reset the form data
    setFormData({
      email: '',
      password: '',
      repeatPassword: '',
      userType: '',
      firstName: '',
      lastName: '',
    });
    setIcon(eyeOff);
    setShowPassword(false);
    setPasswordError('');
    setErrors({
      email: '',
      password: '',
      repeatPassword: '',
      firstName: '',
      lastName: '',
    })
    setRegistered(false)
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    validateCurrentStep(formData, step, setErrors, setValid);

    if (valid) {
      try {
        // Send form data to the server via POST request
        const response = await axios.post('http://localhost:8000/api/register/', formData);

        // Check the response for success
        if (response.data && response.data.status === 'success') {
          console.log('Filtered Data for Submission:', formData);
          // Set registered state to true
          setRegistered(true);

          // Handle redirection after successful registration (e.g., navigate to another page)
          // TODO
        }
      } catch (error) {
        // Handle error response
        if (axios.isAxiosError(error) && error.response) {
          console.error('Registration error: ', error.response.data);
        } else {
          console.error('An unexpected error occurred: ', error);
        }
      }
    }
  };

  const checkPartialForm = () => {

    // @ts-ignore
    if(Object.keys(formData).length >= formlength[formData.userType][step - 1]){
      validateCurrentStep(formData, step, setErrors, setValid)
      if (valid) {
          setStep(step + 1); // Move to the next step when "Next" is clicked
          setPasswordError('');
          setErrors({ email: '', lastName: '', password: '', repeatPassword: '', firstName: '' })
          if (formData.repeatPassword !== formData.password) {
            setPasswordError('\n Passwords do not match.');
          }
      }
    }
    else{
      setErrors({ email: '', lastName: '', password: '', repeatPassword: '', firstName: 'Fill the empty inputs.'})
    }


  }


  return (
          <Modal show={show} onHide={handleModalClose}>
            <Modal.Header closeButton>
              <Modal.Title>Register</Modal.Title>
            </Modal.Header>
            <Modal.Body>
              <form onSubmit={handleSubmit}>
                {/* Step 1: Email, Password, Repeat Password */}
                {step === 1 && (
                  <>
                    {/* first name Field */}
                    <div className="mb-3">
                      <label htmlFor="firstName" className="form-label">First Name</label>
                      <input
                        type="text"
                        className="form-control"
                        id="firstName"
                        placeholder="Enter your first name"
                        value={formData.firstName}
                        onChange={handleChange}
                        required
                      />
                    </div>
                    {/* last name Field */}
                    <div className="mb-3">
                      <label htmlFor="lastName" className="form-label">Last Name</label>
                      <input
                        type="text"
                        className="form-control"
                        id="lastName"
                        placeholder="Enter your last name"
                        value={formData.lastName}
                        onChange={handleChange}
                        required
                      />
                    </div>
                    {/* Email Field */}
                    <div className="mb-3">
                      <label htmlFor="email" className="form-label">Email</label>
                      <input
                        type="email"
                        className="form-control"
                        id="email"
                        placeholder="Enter your email"
                        value={formData.email}
                        onChange={handleChange}
                        required
                      />
                      <div className="invalid-feedback">
                        Please provide a username.
                      </div>
                    </div>

                    {/* Password Field */}
                    <div className="mb-3">
                      <label htmlFor="password" className="form-label">Password</label>
                      <input
                        type={showPassword ? 'text' : 'password'}
                        className="form-control"
                        id="password"
                        placeholder="Enter your password"
                        value={formData.password}
                        onChange={handleChange}
                        required
                      />
                      <span className="flex justify-around items-center" onClick={handleToggle}>
                    <small className="text-danger">{passwordError}</small>
                  <Icon icon={icon} size={25} />
              </span>
                    </div>

                    {/* Repeat Password Field */}
                    <div className="mb-3">
                      <label htmlFor="repeatPassword" className="form-label">Repeat Password</label>
                      <input
                        type={showPasswordRepeat ? 'text' : 'password'}
                        className="form-control"
                        id="repeatPassword"
                        placeholder="Repeat your password"
                        value={formData.repeatPassword}
                        onChange={handleChange}
                        required
                      />
                      <span className="flex justify-around items-center" onClick={handleToggleRepeat}>
                  <Icon icon={iconRepeat} size={25} />
              </span>
                    </div>

                    {/* Dynamically generate options from array */}
                    <div className="mb-3">
                      <label htmlFor="userType" className="form-label">User Type</label>
                      <select
                        className="form-select"
                        id="userType"
                        value={formData.userType}
                        onChange={handleChange}
                        required
                      >
                        <option value="">Select User Type</option>
                        {userTypes.map((type) => (
                          <option key={type} value={type}>
                            {t(`userTypes.${type}`)}
                          </option>
                        ))}
                      </select>
                    </div>

                    {/* Next Button */}
                    {formData.userType !== '' && <div className="d-grid">
                      <Button
                        type="button"
                        className="btn btn-primary"
                        onClick={checkPartialForm}
                      >
                        <img className="ms-2" src="Arrow right.svg" alt="Next" />
                      </Button>

                    </div>}

                  </>
                )}


                {/* Step 2: Additional Fields Based on User Type */}
                {step === 2 && (
                  <>
                    {formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="age" className="form-label">Birth Date</label>
                        <input
                          type="date"
                          className="form-control"
                          id="age"
                          value={formData.age as string || ''}
                          onChange={handleChange}
                          required
                        />
                      </div>
                    )}

                    {
                      formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="sex" className="form-label">Sex</label>
                        <Select
                          closeMenuOnSelect={true}
                          components={animatedComponents}
                          // @ts-ignore
                          options={options}
                          value={formData.sex}
                          id="sex"
                          onChange={(selectedOptions) => {
                            setFormData({
                              ...formData,
                              sex: selectedOptions as string// This is where we set the selected options
                            });
                          }}
                          required={true}
                        />
                      </div>
                    )}

                    {formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="diagnosis" className="form-label">Diagnosis</label>
                        <input
                          type="text"
                          className="form-control"
                          id="diagnosis"
                          placeholder="Enter patient-specific information"
                          value={formData.diagnosis as string || ''}
                          onChange={handleChange}
                          required
                        />
                      </div>
                    )}

                    {formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="function" className="form-label">Function</label>
                        <Select
                          closeMenuOnSelect={true}
                          components={animatedComponents}
                          // @ts-ignore
                          options={options}
                          value={formData.function}
                          id="function"
                          onChange={(selectedOptions) => {
                            setFormData({
                              ...formData,
                              function: selectedOptions as string // This is where we set the selected options
                            });
                          }}
                          required={true}
                        />
                      </div>
                    )}

                    {formData.userType === 'therapist' && (
                      <div className="mb-3">
                        <label htmlFor="specialisation" className="form-label">Specialisation</label>
                        <Select
                          closeMenuOnSelect={true}
                          components={animatedComponents}
                          // @ts-ignore
                          options={options}
                          value={formData.specialisation || ''}
                          id="clinic"
                          onChange={(selectedOptions) => {
                            setFormData({
                              ...formData,
                              specialisation: selectedOptions as string // This is where we set the selected options
                            });
                          }}
                          required={true}
                        />
                      </div>
                    )}

                    {(formData.userType === 'therapist' || formData.userType === 'researcher') && (
                      <div className="mb-3">
                        <label htmlFor="clinic" className="form-label">{t("clinic")}</label>
                        <Select
                          closeMenuOnSelect={false}
                          components={animatedComponents}
                          isMulti
                          // @ts-ignore
                          options={options}
                          value={formData.clinic || []}
                          id="clinic"
                          onChange={(selectedOptions) => {
                            setFormData({
                              ...formData,
                              clinic: selectedOptions as string[]
                            });
                          }}
                          required={true}
                        />
                      </div>
                    )}


                    {formData.userType === 'researcher' && (
                      <div className="mb-3">
                        <label htmlFor="researcherInfo" className="form-label">Researcher Info</label>
                        <input
                          type="text"
                          className="form-control"
                          id="researcherInfo"
                          placeholder="Enter researcher-specific information"
                          value={formData.researcherInfo as string || ''}
                          onChange={handleChange}
                          required
                        />
                      </div>
                    )}

                    {formData.userType === 'admin' && (
                      <div className="mb-3">
                        <label htmlFor="adminInfo" className="form-label">Admin Info</label>
                        <input
                          type="text"
                          className="form-control"
                          id="adminInfo"
                          placeholder="Enter admin-specific information"
                          value={formData.adminInfo as string || ''}
                          onChange={handleChange}
                          required
                        />
                      </div>
                    )}

                    {/* Submit Button */}
                    {(formData.userType === 'therapist' || formData.userType === 'researcher') && (
                      <div className="d-grid">
                        <Button
                          type="submit"
                          className="btn btn-success"
                          hidden={registered}
                        >
                          <img className="ms-2" src="Arrow right.svg" alt="Submit" />
                        </Button>
                      </div>
                    )}

                    {/* Next Button */}
                    {formData.userType === 'patient' && (
                      <div className="d-grid">
                        <Button
                          type="button"
                          className="btn btn-primary"
                          onClick={checkPartialForm}
                        >
                          <img className="ms-2" src="Arrow right.svg" alt="Next" />
                        </Button>
                      </div>
                    )}

                    {/* Back Button */}
                    <div className="d-grid">
                      <Button
                        type="button"
                        className="btn btn-primary"
                        onClick={handleBack}
                        hidden={registered}
                      >
                        <img className="ms-2" src="Arrow left.svg" alt="Back" />
                      </Button>
                    </div>
                  </>
                )}
                {step === 3 && (
                  <>
                    {formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="professionalStatus" className="form-label">Professional Status</label>
                        <Select
                          closeMenuOnSelect={true}
                          components={animatedComponents}
                          // @ts-ignore
                          options={options}
                          value={formData.professionalStatus}
                          id="professionalStatus"
                          onChange={(selectedOptions) => {
                            setFormData({
                              ...formData,
                              professionalStatus: selectedOptions as string// This is where we set the selected options
                            });
                          }}
                          required={true}
                        />
                      </div>
                    )}

                    {formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="levelOfEducation" className="form-label">Level of Education</label>
                        <Select
                          closeMenuOnSelect={true}
                          components={animatedComponents}
                          // @ts-ignore
                          options={options}
                          value={formData.levelOfEducation}
                          id="levelOfEducation"
                          onChange={(selectedOptions) => {
                            setFormData({
                              ...formData,
                              levelOfEducation: selectedOptions as string // This is where we set the selected options
                            });
                          }}
                          required={true}
                        />
                      </div>
                    )}

                    {formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="civilStatus" className="form-label">Civil Status</label>
                        <Select
                          closeMenuOnSelect={true}
                          components={animatedComponents}
                          // @ts-ignore
                          options={options}
                          value={formData.civilStatus}
                          id="civilStatus"
                          onChange={(selectedOptions) => {
                            setFormData({
                              ...formData,
                              civilStatus: selectedOptions as string // This is where we set the selected options
                            });
                          }}
                          required={true}
                        />
                      </div>
                    )}
                    {/* Next Button */}
                    <div className="d-grid">
                      <Button
                        type="button"
                        className="btn btn-primary"
                        onClick={checkPartialForm}
                      >
                        <img className="ms-2" src="Arrow right.svg" alt="Next" />
                      </Button>
                    </div>
                    {/* Back Button */}
                    <div className="d-grid">
                      <Button
                        type="button"
                        className="btn btn-primary"
                        onClick={handleBack}
                      >
                        <img className="ms-2" src="Arrow left.svg" alt="Back" />
                      </Button>
                    </div>
                  </>
                )}
                {step === 4 && (
                  <>
                    {formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="lifestyle" className="form-label">lifestyle</label>
                        <Select
                          closeMenuOnSelect={false}
                          components={animatedComponents}
                          isMulti
                          // @ts-ignore
                          options={options}
                          value={formData.lifestyle}
                          id="lifestyle"
                          onChange={(selectedOptions) => {
                            setFormData({
                              ...formData,
                              lifestyle: selectedOptions as string[]// This is where we set the selected options
                            });
                          }}
                          required={true}
                        />
                      </div>
                    )}

                    <div className="mb-3">
                      <label htmlFor="lifeGoals" className="form-label">Life Goals</label>
                      <Select
                        closeMenuOnSelect={false}
                        components={animatedComponents}
                        isMulti
                        // @ts-ignore
                        options={options}
                        value={formData.lifeGoals}
                        id="lifeGoals"
                        onChange={(selectedOptions) => {
                          setFormData({
                            ...formData,
                            lifeGoals: selectedOptions as string[]// This is where we set the selected options
                          });
                        }}
                        required={true}
                      />
                    </div>

                    {formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="medicationIntake" className="form-label">Medication intake</label>
                        <input
                          type="text"
                          className="form-control"
                          id="medicationIntake"
                          placeholder="Enter patient-specific information"
                          value={formData.medicationIntake as string || ''}
                          onChange={handleChange}
                          required
                        />
                      </div>
                    )}

                    {formData.userType === 'patient' && (
                      <div className="mb-3">
                        <label htmlFor="socialSupport" className="form-label">Social Support</label>
                        <input
                          type="text"
                          className="form-control"
                          id="socialSupport"
                          placeholder="Enter patient-specific information"
                          value={formData.socialSupport as string || ''}
                          onChange={handleChange}
                          required
                        />
                      </div>
                    )}

                    <div className="d-grid">
                      <Button
                        hidden={registered}
                        type="submit"
                        className="btn btn-success"
                      >
                        Submit
                      </Button>
                    </div>
                    {/* Back Button */}
                    <div className="d-grid">
                      <Button
                        type="button"
                        className="btn btn-primary"
                        onClick={handleBack}
                        hidden={registered}
                      >
                        <img className="ms-2" src="Arrow left.svg" alt="Back" />
                      </Button>
                    </div>
                  </>
                )}
                {Object.values(errors).some(value => value !== '') && <div className="alert alert-danger">
                  {Object.values(errors).map((error) => (
                    <div>{error}</div>
                  ))}
                </div>
                }
                {registered && <div className="alert alert-success">
                  <div>You have been Registered. Your account information has been sent to the given email.</div>
                </div>}

              </form>
            </Modal.Body>
          </Modal>
  );
};

export default FormRegister;
