import React from 'react';
import { Navbar, Nav, Container } from 'react-bootstrap';
import { useTranslation } from 'react-i18next';
// @ts-ignore
import flagEN from '../assets/flags/gb.png';
// @ts-ignore
import flagIT from '../assets/flags/it.png';
// @ts-ignore
import flagFR from '../assets/flags/fr.png';
// @ts-ignore
import flagDE from '../assets/flags/de.png';
import { Link } from 'react-router-dom';
import { alignPropType } from 'react-bootstrap/types'
interface HeaderProps {
  isLoggedIn: boolean;
}

const Header: React.FC<HeaderProps> = ({ isLoggedIn }) => {

  const userType: string = "patient"//localStorage.getItem('userType'); TODO

  const { t, i18n } = useTranslation();
  const switchLanguage = () => {
    const languages = ['en', 'it', 'fr', 'de'];
    const currentLanguage = i18n.language;
    const nextIndex = (languages.indexOf(currentLanguage) + 1) % languages.length;
    i18n.changeLanguage(languages[nextIndex]);
  };

  const getFlag = () => {
    switch (i18n.language) {
      case 'en':
        return flagEN;
      case 'it':
        return flagIT;
      case 'fr':
        return flagFR;
      case 'de':
        return flagDE;
      default:
        return flagEN; // Default to English flag
    }
  };


  const handleLogout = () => {
      // Clear session storage
      sessionStorage.removeItem('user'); // Make sure to clear session storage properly
      // Redirect to home or login page
      window.location.href = '/'; // Use this for full-page reload after logout
  };

  return (
    <Navbar expand="lg" className="bg-body-tertiary">
      <Container>
        {!isLoggedIn && (
          <><Navbar.Brand as={Link} to="/">Logo</Navbar.Brand><Navbar.Brand onClick={switchLanguage}>
            <img src={getFlag()} alt={t('switch language')} style={{ cursor: 'pointer' }} />
          </Navbar.Brand></>
          )}

        {isLoggedIn && (

          <Navbar.Collapse id="basic-navbar-nav">
            <Nav className="me-auto">
              {userType === "patient" && (
                <Nav.Link as={Link} to="/patient">
                  {t("home")}
                </Nav.Link>
              )}
              {userType === "therapist" && (
                <Nav.Link as={Link} to="/therapist">
                  {t("home")}
                </Nav.Link>
              )}
              {userType === "researcher" && (
                <Nav.Link as={Link} to="/researcher">
                  {t("home")}
                </Nav.Link>
              )}
              {(userType === "researcher" || userType === "therapist") && (
                <>
                  <Nav.Link as={Link} to="/addcontent">
                    {t("addcontent")}
                  </Nav.Link>
                  <Nav.Link as={Link} to="/profile">
                    {t("profile")}
                  </Nav.Link>
                </>
              )}
            </Nav>
            <Nav className="ms-auto">
              <Nav.Link onClick={handleLogout}>
                {t("logout")}
              </Nav.Link>
            </Nav>
          </Navbar.Collapse>
        )}
        {(userType !== "patient") && (
        <Navbar.Brand onClick={switchLanguage}>
          <img src={getFlag()} alt={t("switch language")} style={{ cursor: 'pointer' }} />
        </Navbar.Brand>
        )}
      </Container>
    </Navbar>
  );
};

export default Header;
