import { makeAutoObservable, action } from "mobx";
import axios from "axios";

class AuthStore {
  email: string = '';
  password: string = '';
  isAuthenticated: boolean = false;
  loginError: string = '';
  userType: string = ''; // Add userType to store

  constructor() {
    makeAutoObservable(this, {
      setEmail: action,
      setPassword: action,
      setAuthenticated: action,
      setLoginError: action,
      loginWithHttp: action,
      reset: action,
      logout: action,
      deleteUser: action,
      checkAuthentication: action,
    });
  }

  // Set the email in the store
  setEmail(email: string) {
    this.email = email;
  }

  // Set the password in the store
  setPassword(password: string) {
    this.password = password;
  }

  // Set the isAuthenticated value in the store
  setAuthenticated(isAuthenticated: boolean) {
    this.isAuthenticated = isAuthenticated;
  }

  // Set the loginError value in the store
  setLoginError(loginError: string) {
    this.loginError = loginError;
  }

  // HTTP login fallback in case WebSocket fails
  async loginWithHttp() {
    try {
      const response = await axios.post('/api/login', {
        email: this.email,
        password: this.password,
      });

      if (response.data && response.data.status === 'success') {
        this.setAuthenticated(true);
        this.setLoginError('');
        this.userType = response.data.userType; // Set the userType from the response

        // Store the userType and token in sessionStorage for navigation & state persistence
        sessionStorage.setItem('userType', response.data.userType);
        sessionStorage.setItem('token', response.data.token);
      } else {
        this.setLoginError('Invalid credentials, please try again.');
      }
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
    } catch (error) {
      this.setLoginError('Login failed. Please check your credentials or try again later.');
    }
  }

  // Reset the store to initial state
  reset() {
    this.email = '';
    this.password = '';
    this.setLoginError('');
    this.isAuthenticated = false;
    this.userType = ''; // Reset userType
  }

  // Logout and clear the stored data
  logout() {
    this.reset();
    sessionStorage.removeItem('userType');
    sessionStorage.removeItem('token');
  }

  // New method to delete the user
  deleteUser() {
    // Here you can make an API call to delete the user on the server if necessary
    console.log(`Deleting user: ${this.email}`);

    this.email = '';
    this.password = '';
    this.setLoginError('');
    this.isAuthenticated = false;
    this.userType = ''; // Reset userType

    // Clear any session storage, tokens, etc.
    sessionStorage.removeItem('token');

    // Optionally, redirect the user to a different page (e.g., home or login)
    console.log('User account deleted successfully.');
  }

  // Check if the user is authenticated based on sessionStorage (useful on page reload)
  checkAuthentication() {
    const token = sessionStorage.getItem('token');
    const storedUserType = sessionStorage.getItem('userType');

    if (token) {
      this.setAuthenticated(true);
      this.userType = storedUserType as string;
    }
  }
}

const authStore = new AuthStore();
export default authStore;
