import React, { useState } from 'react';
import { observer } from 'mobx-react-lite';
import authStore from "../../stores/authStore"; // Use authStore
import { Modal } from 'react-bootstrap';
import { Icon } from 'react-icons-kit';
import { eyeOff } from 'react-icons-kit/feather/eyeOff';
import { eye } from 'react-icons-kit/feather/eye';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import apiClient from '../../api/client'; // Centralized axios instance

interface LoginFormProps {
  show: boolean;
  handleClose: () => void;
  pageType: 'regular' | 'patient'; // New prop to indicate the page type
}

const LoginForm: React.FC<LoginFormProps> = ({ show, handleClose, pageType }) => {
  const navigate = useNavigate();
  const { t } = useTranslation();
  const [icon, setIcon] = useState(eyeOff);
  const [showPassword, setShowPassword] = useState(false);
  authStore.setLoginError('');

  // Toggle password visibility
  const handleToggle = () => {
    setShowPassword(!showPassword);
    setIcon(showPassword ? eyeOff : eye);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      // Using POST to send credentials
      const response = await apiClient.post('/login/', {
        email: authStore.email,
        password: authStore.password,
      });

      if (response.status === 200) {
        // Successful login
        authStore.setAuthenticated(true);
        authStore.setLoginError(''); // Clear any previous login error
        navigate('/' + authStore.userType);
      }
    } catch (error: any) {
      // Handle errors more effectively without ignoring TypeScript warnings
      if (error.response) {
        authStore.setLoginError(`Login failed: ${error.response.data.message}`);
      } else {
        authStore.setLoginError('Connection error.');
      }
    }
  };


  const handleModalClose = () => {
    handleClose();  // This will hide the modal
    authStore.reset();  // Reset the store data after the modal is closed
  };

  const handleForgotPassword = () => {
    navigate('/forgot-password');
  };

  return (
    <Modal show={show} onHide={handleModalClose}>
      <Modal.Header closeButton>
        <Modal.Title>{t('Login')}</Modal.Title>
      </Modal.Header>
      <Modal.Body>
        <form onSubmit={handleSubmit}>
          {/* Email input */}
          <div className="mb-3">
            <label htmlFor="email" className="form-label">{pageType === 'patient' ? t('Patient Email') : t('Email')}</label>
            <input
              type="email"
              className="form-control"
              id="email"
              value={authStore.email}
              onChange={(e) => authStore.setEmail(e.target.value)}
              placeholder={t('Enter email')}
              required
            />
          </div>

          {/* Password input */}
          <div className="mb-3 position-relative">
            <label htmlFor="password" className="form-label">{pageType === 'patient' ? t('Patient Password') : t('Password')}</label>
            <input
              type={showPassword ? 'text' : 'password'}
              className="form-control"
              id="password"
              value={authStore.password}
              onChange={(e) => authStore.setPassword(e.target.value)}
              placeholder={t('Enter password')}
              required
            />
            <span
              className="position-absolute end-0 top-50 translate-middle-y me-3"
              onClick={handleToggle}
              style={{ cursor: 'pointer' }}
            >
              <Icon icon={icon} size={20} />
            </span>
          </div>

          {/* Forgot Password link */}
          <div className="mt-3">
            <button
              type="button"
              className="btn btn-link"
              onClick={handleForgotPassword}
            >
              {t('Forgot Password?')}
            </button>
          </div>

          {/* Login error */}
          {authStore.loginError && (
            <div className="alert alert-danger">{authStore.loginError}</div>
          )}

          {/* Submit button */}
          <button type="submit" className="btn btn-primary">
            {t('Login')}
          </button>
        </form>
      </Modal.Body>
    </Modal>
  );
};

export default observer(LoginForm);